record.field:
for rec in records:
    for line in rec.qurbani_order_line_ids:
        distribution_schedule = env['distribution.schedule'].search([('day_id', '=', line.day_id.id), ('hijri_id', '=', line.hijri_id.id), ('pos_product_ids', 'in', [line.product_id.id]), ('start_time', '=', line.start_time), ('end_time', '=', line.end_time), ('location_id', '=', line.distribution_id.id)], limit=1)

        if distribution_schedule:
            actual_slaughter_slot_demand = env['qurbani.slaughter.slot.demand'].search([('day_id', '=', line.day_id.id), ('hijri_id', '=', line.hijri_id.id), ('inventory_product_id', '=', distribution_schedule.inventory_product_id.id), ('end_time', '=', distribution_schedule.slaughter_schedule_id.end_time), ('slaughter_location_id', '=', distribution_schedule.slaughter_location_id.id)], limit=1)
            wrong_slaughter_slot_demand = env['qurbani.slaughter.slot.demand'].search([('day_id', '=', 1), ('hijri_id', '=', line.hijri_id.id), ('inventory_product_id', '=', distribution_schedule.inventory_product_id.id), ('end_time', '=', distribution_schedule.slaughter_schedule_id.end_time), ('slaughter_location_id', '=', distribution_schedule.slaughter_location_id.id)], limit=1)

            if actual_slaughter_slot_demand:
                actual_slaughter_slot_demand['booked_hissa'] += line.quantity
                actual_slaughter_slot_demand['current_hissa'] += line.quantity
                actual_slaughter_slot_demand['remaining_hissa'] -= line.quantity
            if wrong_slaughter_slot_demand:
                wrong_slaughter_slot_demand['booked_hissa'] -= line.quantity
                wrong_slaughter_slot_demand['current_hissa'] -= line.quantity
                wrong_slaughter_slot_demand['remaining_hissa'] += line.quantity
